import express from "express";
import path from "path";
import { createServer as createViteServer } from "vite";
import { fileURLToPath } from 'url';
import fs from "fs";
import fsp from "fs/promises";

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const DB_FILE = path.resolve(process.cwd(), "data", "pharmacy_db.json");

interface Medicine {
  id: number;
  name: string;
  company: string;
  salt: string;
  purchasePrice: number;
  sellingPrice: number;
  stock: number;
  expiry: string;
  shelf?: string;
  supplier?: string;
}

interface CartItem extends Medicine {
  qty: number;
}

interface Bill {
  billNo: string;
  date: string;
  customer: string;
  items: CartItem[];
  subtotal: number;
  discountPercent: number;
  discountVal: number;
  grandTotal: number;
  cashierName?: string;
}

interface ReturnLog {
  id: string;
  date: string;
  billNo: string;
  medId: number;
  medName: string;
  qty: number;
}

interface Order {
  id: string;
  medId: number;
  medName: string;
  qty: number;
  supplier: string;
  expectedDate: string;
  status: 'Pending' | 'Received' | 'Cancelled';
  createdAt: string;
  receivedDate?: string;
}

interface DB {
  medicines: Medicine[];
  bills: Bill[];
  returns: ReturnLog[];
  orders: Order[];
}

// Helpers for Reading & Writing database
async function readDb(): Promise<DB> {
  try {
    if (!fs.existsSync(DB_FILE)) {
      // Return empty database structure
      return { medicines: [], bills: [], returns: [], orders: [] };
    }
    const data = await fsp.readFile(DB_FILE, "utf-8");
    return JSON.parse(data) as DB;
  } catch (error) {
    console.error("Error reading db file, returning empty structure", error);
    return { medicines: [], bills: [], returns: [], orders: [] };
  }
}

async function writeDb(db: DB): Promise<boolean> {
  try {
    const parentDir = path.dirname(DB_FILE);
    if (!fs.existsSync(parentDir)) {
      await fsp.mkdir(parentDir, { recursive: true });
    }
    await fsp.writeFile(DB_FILE, JSON.stringify(db, null, 2), "utf-8");
    return true;
  } catch (error) {
    console.error("Error writing db file", error);
    return false;
  }
}

async function startServer() {
  const app = express();
  const PORT = 3000;

  app.use(express.json());

  // Ensure DB file directories are well prepped
  const initialDb = await readDb();
  if (initialDb.medicines.length === 0) {
    // If empty or freshly made, populate with defaults
    const defaultData: DB = {
      medicines: [
        { id: 101, name: "Paracetamol 500mg (Napa)", company: "Beximco Pharmaceuticals", salt: "Paracetamol", purchasePrice: 22.0, sellingPrice: 30.0, stock: 145, expiry: "2027-12-15", shelf: "Rack A-1" },
        { id: 102, name: "Azithromycin 250mg", company: "Square Pharmaceuticals", salt: "Azithromycin", purchasePrice: 55.0, sellingPrice: 72.0, stock: 75, expiry: "2026-12-20", shelf: "Rack B-3" },
        { id: 103, name: "Amoxicillin 500mg (Moxacil)", company: "Renata Limited", salt: "Amoxicillin", purchasePrice: 38.0, sellingPrice: 50.0, stock: 8, expiry: "2027-09-10", shelf: "Rack A-2" },
        { id: 104, name: "Cetirizine 10mg (Atova)", company: "Incepta Pharmaceuticals", salt: "Cetirizine", purchasePrice: 15.0, sellingPrice: 25.0, stock: 190, expiry: "2027-03-01", shelf: "Rack C-1" },
        { id: 105, name: "Omeprazole 20mg (Seclo)", company: "Square Pharmaceuticals", salt: "Omeprazole", purchasePrice: 42.0, sellingPrice: 58.0, stock: 3, expiry: "2026-08-30", shelf: "Rack D-2" },
        { id: 106, name: "Metformin 500mg", company: "ACI Limited", salt: "Metformin", purchasePrice: 28.0, sellingPrice: 40.0, stock: 55, expiry: "2027-07-15", shelf: "Rack E-4" },
        { id: 107, name: "Ibuprofen 400mg", company: "Opsonin Pharma", salt: "Ibuprofen", purchasePrice: 22.0, sellingPrice: 35.0, stock: 0, expiry: "2026-05-01", shelf: "Rack F-1" },
        { id: 108, name: "Dolo 650mg", company: "Micro Labs", salt: "Paracetamol", purchasePrice: 24.0, sellingPrice: 33.0, stock: 6, expiry: "2027-02-28", shelf: "Rack A-1" }
      ],
      bills: [],
      returns: [],
      orders: []
    };
    await writeDb(defaultData);
  }

  // API Route - Get Health Status
  app.get("/api/health", (req, res) => {
    res.json({ status: "ok", time: new Date() });
  });

  // API Route - User Login Simulation
  app.post("/api/auth/login", (req, res) => {
    const { username, password, role } = req.body;
    
    const auth: Record<string, { pass: string; role: string }> = {
      admin: { pass: 'admin123', role: 'admin' },
      cashier: { pass: 'cash123', role: 'cashier' },
      stock_manager: { pass: 'stock123', role: 'stock_manager' }
    };

    const user = auth[username.toLowerCase()];
    if (user && user.pass === password && user.role === role) {
      res.json({
        success: true,
        username: username,
        role: role,
        token: `mock-jwt-token-for-${username}`
      });
    } else {
      res.status(401).json({ success: false, message: "Invalid credentials or mismatched role" });
    }
  });

  // API Route - Get Medicines (Stock list)
  app.get("/api/medicines", async (req, res) => {
    const db = await readDb();
    res.json(db.medicines);
  });

  // API Route - Add New Medicine
  app.post("/api/medicines", async (req, res) => {
    const db = await readDb();
    const { name, company, salt, purchasePrice, sellingPrice, stock, expiry, shelf } = req.body;

    if (!name || !company || isNaN(sellingPrice)) {
      return res.status(400).json({ error: "Medicine name, company, and selling price are required" });
    }

    const newMed: Medicine = {
      id: Date.now() % 100000 + 200,
      name,
      company,
      salt: salt || "Generic",
      purchasePrice: Number(purchasePrice) || sellingPrice * 0.7,
      sellingPrice: Number(sellingPrice),
      stock: Number(stock) || 0,
      expiry: expiry || "",
      shelf: shelf || "Rack A-1"
    };

    db.medicines.push(newMed);
    await writeDb(db);
    res.status(201).json(newMed);
  });

  // API Route - Update Medicine Details (Including stock additions)
  app.put("/api/medicines/:id", async (req, res) => {
    const db = await readDb();
    const id = parseInt(req.params.id);
    const index = db.medicines.findIndex(m => m.id === id);

    if (index === -1) {
      return res.status(404).json({ error: "Medicine not found" });
    }

    const current = db.medicines[index];
    const updated = {
      ...current,
      ...req.body,
      // Keep safety formats
      purchasePrice: isNaN(req.body.purchasePrice) ? current.purchasePrice : Number(req.body.purchasePrice),
      sellingPrice: isNaN(req.body.sellingPrice) ? current.sellingPrice : Number(req.body.sellingPrice),
      stock: isNaN(req.body.stock) ? current.stock : Number(req.body.stock)
    };

    db.medicines[index] = updated;
    await writeDb(db);
    res.json(updated);
  });

  // API Route - Delete Medicine
  app.delete("/api/medicines/:id", async (req, res) => {
    const db = await readDb();
    const id = parseInt(req.params.id);
    const exists = db.medicines.some(m => m.id === id);

    if (!exists) {
      return res.status(404).json({ error: "Medicine not found" });
    }

    db.medicines = db.medicines.filter(m => m.id !== id);
    await writeDb(db);
    res.json({ success: true, message: "Medicine removed successfully" });
  });

  // API Route - Get Sale Bills
  app.get("/api/bills", async (req, res) => {
    const db = await readDb();
    res.json(db.bills);
  });

  // API Route - Create Sell Bill (Stock deduction + transaction handling)
  app.post("/api/bills", async (req, res) => {
    const db = await readDb();
    const { customer, items, discountPercent, discountVal, subtotal, grandTotal, cashierName } = req.body;

    if (!items || !Array.isArray(items) || items.length === 0) {
      return res.status(400).json({ error: "Cart is empty" });
    }

    // Safety checks: double-check that we have enough stock for each item in DB
    for (const item of items) {
      const realMed = db.medicines.find(m => m.id === item.id);
      if (!realMed) {
        return res.status(400).json({ error: `Medicine '${item.name}' does not exist in inventory` });
      }
      if (realMed.stock < item.qty) {
        return res.status(400).json({ error: `Not enough stock for '${realMed.name}'. Available: ${realMed.stock}, requested: ${item.qty}` });
      }
      if (realMed.expiry && new Date(realMed.expiry) < new Date()) {
        return res.status(400).json({ error: `Medicine '${realMed.name}' has already expired and cannot be sold` });
      }
    }

    // Deduce stock securely
    for (const item of items) {
      const realMedVal = db.medicines.find(m => m.id === item.id)!;
      realMedVal.stock -= item.qty;
    }

    // Generate Invoice ID
    const nextBillNo = `MC-${db.bills.length + 2101}`;
    const newBill: Bill = {
      billNo: nextBillNo,
      date: new Date().toLocaleDateString(),
      customer: customer || "Guest Customer",
      items,
      subtotal: Number(subtotal),
      discountPercent: Number(discountPercent) || 0,
      discountVal: Number(discountVal) || 0,
      grandTotal: Number(grandTotal),
      cashierName: cashierName || "Unknown Cashier"
    };

    db.bills.unshift(newBill);
    await writeDb(db);
    res.status(201).json(newBill);
  });

  // API Route - Record Return (Restores stock + adds to log)
  app.post("/api/returns", async (req, res) => {
    const db = await readDb();
    const { billNo, medId, qty } = req.body;

    if (!billNo || !medId || isNaN(qty) || qty <= 0) {
      return res.status(400).json({ error: "Valid billNo, medId, and quantity to return are required" });
    }

    const medicine = db.medicines.find(m => m.id === Number(medId));
    if (!medicine) {
      return res.status(404).json({ error: "Medicine not found in our database" });
    }

    // Restore stock
    medicine.stock += Number(qty);

    const log: ReturnLog = {
      id: `RET-${Date.now()}`,
      date: new Date().toLocaleDateString(),
      billNo,
      medId: Number(medId),
      medName: medicine.name,
      qty: Number(qty)
    };

    db.returns.unshift(log);
    await writeDb(db);

    res.status(201).json({ success: true, log, updatedMedicine: medicine });
  });

  // API Route - Get Returns List
  app.get("/api/returns", async (req, res) => {
    const db = await readDb();
    res.json(db.returns);
  });

  // API Route - Get Purchase Orders
  app.get("/api/orders", async (req, res) => {
    const db = await readDb();
    res.json(db.orders);
  });

  // API Route - Create Purchase Order
  app.post("/api/orders", async (req, res) => {
    const db = await readDb();
    const { medId, qty, supplier, expectedDate } = req.body;

    if (!medId || !qty || isNaN(qty) || qty <= 0 || !supplier) {
      return res.status(400).json({ error: "medId, quantity, and supplier are required" });
    }

    const med = db.medicines.find(m => m.id === Number(medId));
    if (!med) {
      return res.status(404).json({ error: "Requested medicine for purchase order is not found" });
    }

    const orderId = `PO-${Date.now()}`;
    const newOrder: Order = {
      id: orderId,
      medId: Number(medId),
      medName: med.name,
      qty: Number(qty),
      supplier,
      expectedDate: expectedDate || new Date().toISOString().split('T')[0],
      status: 'Pending',
      createdAt: new Date().toLocaleDateString()
    };

    db.orders.unshift(newOrder);
    await writeDb(db);
    res.status(201).json(newOrder);
  });

  // API Route - Receive or Cancel Purchase Order
  app.put("/api/orders/:id", async (req, res) => {
    const db = await readDb();
    const orderId = req.params.id;
    const orderIndex = db.orders.findIndex(o => o.id === orderId);

    if (orderIndex === -1) {
      return res.status(404).json({ error: "Purchase order not found" });
    }

    const { status } = req.body; // 'Received' or 'Cancelled'
    if (status !== 'Received' && status !== 'Cancelled') {
      return res.status(400).json({ error: "Invalid status update. Only 'Received' or 'Cancelled' is allowed." });
    }

    const order = db.orders[orderIndex];
    if (order.status !== 'Pending') {
      return res.status(400).json({ error: `Order is already marked as ${order.status}` });
    }

    order.status = status;
    if (status === 'Received') {
      order.receivedDate = new Date().toLocaleDateString();
      // Add order quantity to actual medicine stock
      const med = db.medicines.find(m => m.id === order.medId);
      if (med) {
        med.stock += order.qty;
      }
    }

    db.orders[orderIndex] = order;
    await writeDb(db);
    res.json({ success: true, order });
  });

  // Vite middleware for development
  if (process.env.NODE_ENV !== "production") {
    const vite = await createViteServer({
      server: { middlewareMode: true },
      appType: "spa",
    });
    app.use(vite.middlewares);
  } else {
    const distPath = path.join(process.cwd(), 'dist');
    app.use(express.static(distPath));
    app.get('*', (req, res) => {
      res.sendFile(path.join(distPath, 'index.html'));
    });
  }

  app.listen(PORT, "0.0.0.0", () => {
    console.log(`Server running on http://localhost:${PORT}`);
  });
}

startServer();
